95: /**
96:  * The checkpoint coordinator coordinates the distributed snapshots of operators and state. It
97:  * triggers the checkpoint by sending the messages to the relevant tasks and collects the checkpoint
98:  * acknowledgements. It also collects and maintains the overview of the state handles reported by
99:  * the tasks that acknowledge the checkpoint.
100:  */
101: public class CheckpointCoordinator {
102: 
103:     private static final Logger LOG = LoggerFactory.getLogger(CheckpointCoordinator.class);
104: 
105:     /** The number of recent checkpoints whose IDs are remembered. */
106:     private static final int NUM_GHOST_CHECKPOINT_IDS = 16;
107: 
108:     // ------------------------------------------------------------------------
109: 
110:     /** Coordinator-wide lock to safeguard the checkpoint updates. */
111:     private final Object lock = new Object();
112: 
113:     /** The job whose checkpoint this coordinator coordinates. */
114:     private final JobID job;
115: 
116:     /** Default checkpoint properties. */
117:     private final CheckpointProperties checkpointProperties;
118: 
119:     /** The executor used for asynchronous calls, like potentially blocking I/O. */
120:     private final Executor executor;
121: 
122:     private final CheckpointsCleaner checkpointsCleaner;
123: 
124:     /** The operator coordinators that need to be checkpointed. */
125:     private final Collection<OperatorCoordinatorCheckpointContext> coordinatorsToCheckpoint;
126: 
127:     /** Map from checkpoint ID to the pending checkpoint. */
128:     @GuardedBy("lock")
129:     private final Map<Long, PendingCheckpoint> pendingCheckpoints;
130: 
131:     /**
132:      * Completed checkpoints. Implementations can be blocking. Make sure calls to methods accessing
133:      * this don't block the job manager actor and run asynchronously.
134:      */
135:     private final CompletedCheckpointStore completedCheckpointStore;
136: 
137:     /**
138:      * The root checkpoint state backend, which is responsible for initializing the checkpoint,
139:      * storing the metadata, and cleaning up the checkpoint.
140:      */
141:     private final CheckpointStorageCoordinatorView checkpointStorageView;
142: 
143:     /** A list of recent expired checkpoint IDs, to identify late messages (vs invalid ones). */
144:     private final ArrayDeque<Long> recentExpiredCheckpoints;
145: 
146:     /**
147:      * Checkpoint ID counter to ensure ascending IDs. In case of job manager failures, these need to
148:      * be ascending across job managers.
149:      */
150:     private final CheckpointIDCounter checkpointIdCounter;
151: 
152:     /**
