830:     private CompletableFuture<Void> triggerTasks(
831:             CheckpointTriggerRequest request, long timestamp, PendingCheckpoint checkpoint) {
832:         // no exception, no discarding, everything is OK
833:         final long checkpointId = checkpoint.getCheckpointID();
834: 
835:         final SnapshotType type;
836:         if (this.forceFullSnapshot && !request.props.isSavepoint()) {
837:             type = FULL_CHECKPOINT;
838:         } else {
839:             type = request.props.getCheckpointType();
840:         }
841: 
842:         final CheckpointOptions checkpointOptions =
843:                 CheckpointOptions.forConfig(
844:                         type,
845:                         checkpoint.getCheckpointStorageLocation().getLocationReference(),
846:                         isExactlyOnceMode,
847:                         unalignedCheckpointsEnabled,
848:                         alignedCheckpointTimeout);
849: 
850:         // send messages to the tasks to trigger their checkpoints
851:         List<CompletableFuture<Acknowledge>> acks = new ArrayList<>();
852:         for (Execution execution : checkpoint.getCheckpointPlan().getTasksToTrigger()) {
853:             if (request.props.isSynchronous()) {
854:                 acks.add(
855:                         execution.triggerSynchronousSavepoint(
856:                                 checkpointId, timestamp, checkpointOptions));
857:             } else {
858:                 acks.add(execution.triggerCheckpoint(checkpointId, timestamp, checkpointOptions));
859:             }
860:         }
861:         return FutureUtils.waitForAll(acks);
862:     }
