1359:     private void completePendingCheckpoint(PendingCheckpoint pendingCheckpoint)
1360:             throws CheckpointException {
1361:         final long checkpointId = pendingCheckpoint.getCheckpointID();
1362:         final CompletedCheckpoint completedCheckpoint;
1363:         final CompletedCheckpoint lastSubsumed;
1364:         final CheckpointProperties props = pendingCheckpoint.getProps();
1365: 
1366:         completedCheckpointStore.getSharedStateRegistry().checkpointCompleted(checkpointId);
1367: 
1368:         try {
1369:             completedCheckpoint = finalizeCheckpoint(pendingCheckpoint);
1370: 
1371:             // the pending checkpoint must be discarded after the finalization
1372:             Preconditions.checkState(pendingCheckpoint.isDisposed() && completedCheckpoint != null);
1373: 
1374:             if (!props.isSavepoint()) {
1375:                 lastSubsumed =
1376:                         addCompletedCheckpointToStoreAndSubsumeOldest(
1377:                                 checkpointId, completedCheckpoint, pendingCheckpoint);
1378:             } else {
1379:                 lastSubsumed = null;
1380:             }
1381: 
1382:             reportCompletedCheckpoint(completedCheckpoint);
1383:             pendingCheckpoint.getCompletionFuture().complete(completedCheckpoint);
1384:         } catch (Exception exception) {
1385:             // For robustness reasons, we need catch exception and try marking the checkpoint
1386:             // completed.
1387:             pendingCheckpoint.getCompletionFuture().completeExceptionally(exception);
1388:             throw exception;
1389:         } finally {
1390:             pendingCheckpoints.remove(checkpointId);
1391:             scheduleTriggerRequest();
1392:         }
1393: 
1394:         cleanupAfterCompletedCheckpoint(
1395:                 pendingCheckpoint, checkpointId, completedCheckpoint, lastSubsumed, props);
1396:     }
