59: public class CheckpointBarrierTracker extends CheckpointBarrierHandler {
60: 
61:     private static final Logger LOG = LoggerFactory.getLogger(CheckpointBarrierTracker.class);
62: 
63:     /**
64:      * The tracker tracks a maximum number of checkpoints, for which some, but not all barriers have
65:      * yet arrived.
66:      */
67:     private static final int MAX_CHECKPOINTS_TO_TRACK = 50;
68: 
69:     // ------------------------------------------------------------------------
70: 
71:     /** The number of open channels. */
72:     private int numOpenChannels;
73: 
74:     /**
75:      * All checkpoints for which some (but not all) barriers have been received, and that are not
76:      * yet known to be subsumed by newer checkpoints.
77:      */
78:     private final ArrayDeque<CheckpointBarrierCount> pendingCheckpoints;
79: 
80:     /** The highest checkpoint ID encountered so far. */
81:     private long latestPendingCheckpointID = -1;
82: 
83:     public CheckpointBarrierTracker(
84:             int totalNumberOfInputChannels,
85:             CheckpointableTask toNotifyOnCheckpoint,
86:             Clock clock,
87:             boolean enableCheckpointAfterTasksFinished) {
88:         super(toNotifyOnCheckpoint, clock, enableCheckpointAfterTasksFinished);
89:         this.numOpenChannels = totalNumberOfInputChannels;
90:         this.pendingCheckpoints = new ArrayDeque<>();
91:     }
92: 
93:     @Override
94:     public void processBarrier(
95:             CheckpointBarrier receivedBarrier, InputChannelInfo channelInfo, boolean isRpcTriggered)
96:             throws IOException {
97:         final long barrierId = receivedBarrier.getId();
98: 
99:         // fast path for single channel trackers. We only go with the fast path
100:         // for new checkpoints, otherwise we might met with the case that
101:         // 1. Received barrier from channel 0 (2 in total) and start a new checkpoint.
102:         // 2. Received EndOfPartition from channel 0.
103:         // 3. Received barrier from channel 1.
104:         // In this case we should finish the existing pending checkpoint.
105:         if (barrierId > latestPendingCheckpointID && numOpenChannels == 1) {
106:             markAlignmentStartAndEnd(barrierId, receivedBarrier.getTimestamp());
107:             notifyCheckpoint(receivedBarrier);
108:             return;
109:         }
110: 
111:         // general path for multiple input channels
112:         if (LOG.isDebugEnabled()) {
113:             LOG.debug("Received barrier for checkpoint {} from channel {}", barrierId, channelInfo);
114:         }
115: 
116:         // find the checkpoint barrier in the queue of pending barriers
117:         CheckpointBarrierCount barrierCount = null;
118:         int pos = 0;
119: 
120:         for (CheckpointBarrierCount next : pendingCheckpoints) {
121:             if (next.checkpointId() == barrierId) {
122:                 barrierCount = next;
123:                 break;
124:             }
125:             pos++;
126:         }
127: 
128:         if (barrierCount != null) {
129:             // add one to the count to that barrier and check for completion
130:             int numChannelsNew = barrierCount.markChannelAligned(channelInfo);
131:             if (numChannelsNew == barrierCount.getTargetChannelCount()) {
132:                 // checkpoint can be triggered (or is aborted and all barriers have been seen)
133:                 // first, remove this checkpoint and all all prior pending
134:                 // checkpoints (which are now subsumed)
135:                 for (int i = 0; i <= pos; i++) {
136:                     pendingCheckpoints.pollFirst();
137:                 }
138: 
139:                 // notify the listener
140:                 if (!barrierCount.isAborted()) {
141:                     triggerCheckpointOnAligned(barrierCount);
142:                 }
143:             }
144:         } else {
145:             // first barrier for that checkpoint ID
146:             // add it only if it is newer than the latest checkpoint.
147:             // if it is not newer than the latest checkpoint ID, then there cannot be a
148:             // successful checkpoint for that ID anyways
149:             if (barrierId > latestPendingCheckpointID) {
150:                 markAlignmentStart(barrierId, receivedBarrier.getTimestamp());
